const LABEL_ARCHIVIERT = '69d64b9011fe02d420b21789';

// Manuelle Koordinaten für Standorte ohne GeoPosition in Fleetster
const GEO_FALLBACK = {
  '6995ae3a23d2b03af2696956': { lat: 50.5956690, lng: 7.1591653 }  // Gut Bentgerhof
};

const locItems = $('Standorte abrufen').all().map(i => i.json);
let locations = locItems;
if (locItems.length === 1 && Array.isArray(locItems[0])) locations = locItems[0];

// Archivierte ausfiltern
const filtered = locations.filter(loc => {
  const labels = (loc.extended && loc.extended.EntityLabels && loc.extended.EntityLabels.labels) || [];
  return !labels.includes(LABEL_ARCHIVIERT);
});

const stations = [];
for (const loc of filtered) {
  let lat = loc.extended && loc.extended.GeoPosition && loc.extended.GeoPosition.latitude;
  let lng = loc.extended && loc.extended.GeoPosition && loc.extended.GeoPosition.longitude;

  // Fallback: manuelle Koordinaten wenn Fleetster keine hat
  if (!lat || !lng) {
    const fb = GEO_FALLBACK[loc._id];
    if (fb) { lat = fb.lat; lng = fb.lng; }
    else { continue; }
  }

  stations.push({
    id: loc._id,
    name: (loc.name || '').trim(),
    city: (loc.city || '').trim(),
    postcode: (loc.postcode || '').trim(),
    street: ((loc.streetName || '') + ' ' + (loc.streetNumber || '')).trim(),
    lat: lat,
    lng: lng,
    comment: loc.comment || ''
  });
}

stations.sort((a, b) => a.name.localeCompare(b.name));

const result = { stations: stations, updated: new Date().toISOString() };
const githubToken = $env.GITHUB_TOKEN || '';

return [{ json: { content: JSON.stringify(result, null, 2), githubToken: githubToken } }];

const fileCheck = $input.first().json;
const content = $('JSON formatieren').first().json.content;
const githubToken = $('JSON formatieren').first().json.githubToken;

// SHA kann direkt oder verschachtelt sein
const sha = fileCheck.sha || (fileCheck.data && fileCheck.data.sha) || null;

const contentBase64 = Buffer.from(content, 'utf-8').toString('base64');

const body = {
  message: 'chore: Standorte aktualisiert (' + new Date().toISOString().slice(0,10) + ')',
  content: contentBase64
};

if (sha) {
  body.sha = sha;
} else {
  throw new Error('SHA konnte nicht ermittelt werden. Response: ' + JSON.stringify(fileCheck).slice(0, 500));
}

return [{ json: { body: body, githubToken: githubToken } }];
